module RefModule (
    input clk,
    input reset,
    input start_connection,
    input connection_success,
    input disconnect,
    output reg [1:0] state // 00: IDLE, 01: CONNECTING, 10: CONNECTED, 11: DISCONNECTED
);

    // State encoding
    parameter IDLE = 2'b00, CONNECTING = 2'b01, CONNECTED = 2'b10, DISCONNECTED = 2'b11;

    always @(posedge clk or posedge reset) begin
        if (reset) begin
            state <= IDLE;
        end else begin
            case (state)
                IDLE: begin
                    if (start_connection) 
                        state <= CONNECTING;
                end
                CONNECTING: begin
                    if (connection_success) 
                        state <= CONNECTED;
                    else if (disconnect)
                        state <= DISCONNECTED;
                end
                CONNECTED: begin
                    if (disconnect)
                        state <= DISCONNECTED;
                end
                DISCONNECTED: begin
                    if (start_connection) 
                        state <= CONNECTING;
                end
            endcase
        end
    end
endmodule
